import{B as e,Q as t,s as n,z as r}from"./chunks/framework.GF8LbaeE.js";var i=JSON.parse(`{"title":"Dashboards","description":"","frontmatter":{},"headers":[],"relativePath":"guide/dashboards.md","filePath":"guide/dashboards.md"}`),a={name:`guide/dashboards.md`};function o(n,i,a,o,s,c){return t(),r(`div`,null,[...i[0]||=[e(`<h1 id="dashboards" tabindex="-1">Dashboards <a class="header-anchor" href="#dashboards" aria-label="Permalink to &quot;Dashboards&quot;">​</a></h1><p>Welcome to the Dashboards guide. This documentation is automatically generated from the latest game features.</p><h2 id="hall-of-fame" tabindex="-1">Hall of Fame <a class="header-anchor" href="#hall-of-fame" aria-label="Permalink to &quot;Hall of Fame&quot;">​</a></h2><p>The Hall of Fame tracks the top players across the entire ATW RPG ecosystem. Ranking is primarily based on the Legacy Score, which combines cumulative fans earned across all managed wrestlers and points from unlocked achievements.</p><p><img src="/all-time-wrestling-rpg/screenshots/hall-of-fame.png" alt="Hall of Fame"></p><hr><h2 id="news-rumors-feed" tabindex="-1">News &amp; Rumors Feed <a class="header-anchor" href="#news-rumors-feed" aria-label="Permalink to &quot;News &amp; Rumors Feed&quot;">​</a></h2><p>A procedural news system that reacts to in-game events across the promotion.</p><p><img src="/all-time-wrestling-rpg/screenshots/dashboards-news-feed.png" alt="News &amp; Rumors Feed"></p><hr><h2 id="show-calendar" tabindex="-1">Show Calendar <a class="header-anchor" href="#show-calendar" aria-label="Permalink to &quot;Show Calendar&quot;">​</a></h2><p>Plan ahead with the integrated calendar. View upcoming weekly shows and major Premium Live Events at a glance.</p><p><img src="/all-time-wrestling-rpg/screenshots/dashboard-calendar.png" alt="Show Calendar"></p><hr><h2 id="wrestler-rankings" tabindex="-1">Wrestler Rankings <a class="header-anchor" href="#wrestler-rankings" aria-label="Permalink to &quot;Wrestler Rankings&quot;">​</a></h2><p>Track the momentum of every wrestler in the promotion. Rankings determine title eligibility and positioning on show cards.</p><p><img src="/all-time-wrestling-rpg/screenshots/dashboard-rankings.png" alt="Wrestler Rankings"></p><hr><h2 id="video-walkthroughs" tabindex="-1">Video Walkthroughs <a class="header-anchor" href="#video-walkthroughs" aria-label="Permalink to &quot;Video Walkthroughs&quot;">​</a></h2><h3 id="wrestler-rankings-1" tabindex="-1">Wrestler Rankings <a class="header-anchor" href="#wrestler-rankings-1" aria-label="Permalink to &quot;Wrestler Rankings&quot;">​</a></h3><p>Click any wrestler&#39;s name in the rankings to jump straight to their full profile — match history, rivalries, title reigns, and injury records are all one click away from this view.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/dashboard-rankings-walkthrough.mp4" type="video/mp4"></video><hr><h3 id="news-rumors-walkthrough" tabindex="-1">News &amp; Rumors Walkthrough <a class="header-anchor" href="#news-rumors-walkthrough" aria-label="Permalink to &quot;News &amp; Rumors Walkthrough&quot;">​</a></h3><p>Admins and bookers can click Generate Monthly Synthesis to have the AI summarise the month&#39;s events into a single narrative dispatch, or Create News to manually write a headline that appears in the feed.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/news-walkthrough.mp4" type="video/mp4"></video><hr><h3 id="hall-of-fame-walkthrough" tabindex="-1">Hall of Fame Walkthrough <a class="header-anchor" href="#hall-of-fame-walkthrough" aria-label="Permalink to &quot;Hall of Fame Walkthrough&quot;">​</a></h3><p>The Hall of Fame is global — every account in the system appears here. Use it to benchmark your career progress against other promoters and set long-term goals for the season.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/hall-of-fame-walkthrough.mp4" type="video/mp4"></video><hr>`,31)]])}var s=n(a,[[`render`,o]]);export{i as __pageData,s as default};